mapper.sql:
FROM hot_cluster hc
WHERE hc.status = 'ACTIVE'

    AND EXISTS (
        SELECT 1
        FROM hot_cluster_item hci
        JOIN hot_item hi ON hi.id = hci.hot_item_id
        WHERE hci.hot_cluster_id = hc.id
          AND hci.removed_at IS NULL
          AND hi.source_type = #{sourceType}
    )


    AND hc.last_seen_at >= #{from}


    AND hc.last_seen_at <= #{to}
